[CmdletBinding(SupportsShouldProcess = $true)]
param(
    [string]$Destination = (Join-Path $env:USERPROFILE '.gemini\config\skills\github\gh-reconcile'),
    [switch]$Force,
    [switch]$SkipBackup
)

$ErrorActionPreference = 'Stop'

$ExpectedZipSha256 = 'bd16a85bce0c3548b7b9011a2ea0eda4550391a069107d0fc824cc8f232b8739'
$EmbeddedZipBase64 = @'

'@

function Write-Utf8NoBom {
    param(
        [Parameter(Mandatory)][string]$Path,
        [Parameter(Mandatory)][string]$Content
    )

    $Parent = Split-Path -Parent $Path
    if ($Parent) {
        New-Item -ItemType Directory -Force -Path $Parent | Out-Null
    }

    $TempPath = "$Path.tmp"
    [System.IO.File]::WriteAllText(
        $TempPath,
        $Content,
        [System.Text.UTF8Encoding]::new($false)
    )
    Move-Item -Path $TempPath -Destination $Path -Force
}

function Get-Sha256 {
    param([Parameter(Mandatory)][string]$Path)
    return (Get-FileHash -Algorithm SHA256 -Path $Path).Hash.ToLowerInvariant()
}

$Timestamp = Get-Date -Format 'yyyyMMdd-HHmmss'
$TempRoot = Join-Path ([System.IO.Path]::GetTempPath()) "gh-reconcile-evidence-$Timestamp-$([guid]::NewGuid().ToString('N').Substring(0,8))"
$EmbeddedZipPath = Join-Path $TempRoot 'gh-reconcile-evidence-pack.zip'
$ExtractRoot = Join-Path $TempRoot 'extract'
$StageRoot = Join-Path $TempRoot 'stage'

try {
    New-Item -ItemType Directory -Force -Path $TempRoot, $ExtractRoot, $StageRoot | Out-Null

    Write-Host 'Decodificando pacote embutido...' -ForegroundColor Cyan
    $ZipBytes = [Convert]::FromBase64String(($EmbeddedZipBase64 -replace '\s', ''))
    [System.IO.File]::WriteAllBytes($EmbeddedZipPath, $ZipBytes)

    $ActualZipSha256 = Get-Sha256 -Path $EmbeddedZipPath
    if ($ActualZipSha256 -ne $ExpectedZipSha256) {
        throw "Falha de integridade do pacote. Esperado: $ExpectedZipSha256 | Obtido: $ActualZipSha256"
    }

    Write-Host "SHA-256 verificado: $ActualZipSha256" -ForegroundColor Green

    Expand-Archive -LiteralPath $EmbeddedZipPath -DestinationPath $ExtractRoot -Force

    $PackRoot = Join-Path $ExtractRoot 'gh-reconcile-evidence-pack'
    if (-not (Test-Path $PackRoot)) {
        $Candidate = Get-ChildItem -Path $ExtractRoot -Directory | Select-Object -First 1
        if (-not $Candidate) {
            throw 'O pacote foi extraído, mas a raiz esperada não foi encontrada.'
        }
        $PackRoot = $Candidate.FullName
    }

    $RequiredFiles = @(
        'README.md',
        'PACK_MANIFEST.json',
        'docs\EVIDENCE_CATALOG.md',
        'reports\RECONCILIATION_REPORT.md',
        'manifests\run-manifest.template.json',
        'schemas\run-manifest.schema.json',
        'index\evidence-index.template.json'
    )

    foreach ($RelativePath in $RequiredFiles) {
        $CandidatePath = Join-Path $PackRoot $RelativePath
        if (-not (Test-Path $CandidatePath)) {
            throw "Artefato obrigatório ausente no pacote: $RelativePath"
        }
    }

    $Files = Get-ChildItem -Path $PackRoot -Recurse -File
    if ($Files.Count -lt 40) {
        throw "Pacote incompleto: apenas $($Files.Count) arquivos encontrados."
    }

    Write-Host "Pacote validado: $($Files.Count) artefatos." -ForegroundColor Green

    Copy-Item -Path (Join-Path $PackRoot '*') -Destination $StageRoot -Recurse -Force

    if (Test-Path $Destination) {
        $ExistingFiles = Get-ChildItem -Path $Destination -Recurse -File -ErrorAction SilentlyContinue

        if (-not $Force) {
            Write-Host ''
            Write-Host "A skill já existe em: $Destination" -ForegroundColor Yellow
            Write-Host 'Use -Force para integrar os artefatos ao diretório existente.'
            exit 2
        }

        if (-not $SkipBackup) {
            $BackupRoot = "$Destination.backup-$Timestamp"
            Write-Host "Criando backup em: $BackupRoot" -ForegroundColor Cyan
            Copy-Item -Path $Destination -Destination $BackupRoot -Recurse -Force
        }
    }

    if ($PSCmdlet.ShouldProcess($Destination, 'Integrar evidence pack gh-reconcile')) {
        New-Item -ItemType Directory -Force -Path $Destination | Out-Null

        # Integração não destrutiva: preserva SKILL.md e scripts existentes,
        # adicionando/atualizando apenas os artefatos do evidence pack.
        foreach ($SourceFile in Get-ChildItem -Path $StageRoot -Recurse -File) {
            $RelativePath = $SourceFile.FullName.Substring($StageRoot.Length).TrimStart('\', '/')
            $TargetPath = Join-Path $Destination $RelativePath
            $TargetParent = Split-Path -Parent $TargetPath
            New-Item -ItemType Directory -Force -Path $TargetParent | Out-Null
            Copy-Item -LiteralPath $SourceFile.FullName -Destination $TargetPath -Force
        }

        $InstalledFiles = Get-ChildItem -Path $Destination -Recurse -File
        $EvidenceFiles = $InstalledFiles | Where-Object {
            $_.FullName -match '\\(docs|reports|manifests|schemas|fixtures|dashboard|index)\\' -or
            $_.Name -in @('PACK_MANIFEST.json', 'README.md')
        }

        $InstallManifest = [ordered]@{
            schemaVersion = '1.0.0'
            packName = 'gh-reconcile-evidence-pack'
            packVersion = '1.0.0'
            installedAt = (Get-Date).ToString('o')
            destination = $Destination
            embeddedZipSha256 = "sha256:$ExpectedZipSha256"
            installedArtifactCount = $EvidenceFiles.Count
            backupCreated = (-not $SkipBackup)
            status = 'INSTALLED'
        }

        $InstallManifestPath = Join-Path $Destination 'EVIDENCE_PACK_INSTALLATION.json'
        Write-Utf8NoBom -Path $InstallManifestPath -Content ($InstallManifest | ConvertTo-Json -Depth 8)

        Write-Host ''
        Write-Host 'Evidence pack instalado com sucesso.' -ForegroundColor Green
        Write-Host "Destino: $Destination"
        Write-Host "Artefatos do pack: $($EvidenceFiles.Count)"
        Write-Host "Manifesto: $InstallManifestPath"
        Write-Host ''
        Write-Host 'Validação sugerida:' -ForegroundColor Cyan
        Write-Host "Get-Content `"$InstallManifestPath`""
        Write-Host "Get-ChildItem `"$Destination\reports`""
        Write-Host "Get-ChildItem `"$Destination\schemas`""
        Write-Host ''
        Write-Host 'Reinicie ou recarregue o agente/IDE para atualizar a skill global.'
    }
}
finally {
    if (Test-Path $TempRoot) {
        Remove-Item -Path $TempRoot -Recurse -Force -ErrorAction SilentlyContinue
    }
}
